import{_ as a,o as t,c as r,ak as i,ao as s,am as l,an as n}from"./chunks/framework.D56sOg_b.js";const m=JSON.parse('{"title":"快速开始","description":"","frontmatter":{"version":"2.0.0"},"headers":[],"relativePath":"guide/QUICK-START.md","filePath":"guide/QUICK-START.md","lastUpdated":1777342039000}'),o={name:"guide/QUICK-START.md"};function d(h,e,c,p,k,b){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to “快速开始”">​</a></h1><ul><li><a href="https://blog.csdn.net/qq_38765404/article/details/123497710/" target="_blank" rel="noreferrer">快速搭建 Jenkins 服务</a></li><li><a href="https://open.larksuite.com/document/client-docs/bot-v3/add-custom-bot" target="_blank" rel="noreferrer">Lark 自定义机器人指南</a></li><li><a href="https://open.feishu.cn/document/client-docs/bot-v3/add-custom-bot" target="_blank" rel="noreferrer">飞书自定义机器人指南</a></li><li><a href="https://open.dingtalk.com/document/orgapp/custom-robots-send-group-messages" target="_blank" rel="noreferrer">钉钉自定义机器人指南</a></li></ul><h2 id="环境准备" tabindex="-1">环境准备 <a class="header-anchor" href="#环境准备" aria-label="Permalink to “环境准备”">​</a></h2><p>开始之前，请确认运行环境满足以下要求：</p><table tabindex="0"><thead><tr><th>名称</th><th>版本</th></tr></thead><tbody><tr><td>Jenkins</td><td>2.528.3+</td></tr></tbody></table><h2 id="在线安装" tabindex="-1">在线安装 <a class="header-anchor" href="#在线安装" aria-label="Permalink to “在线安装”">​</a></h2><p>当前版本可能无法通过 Jenkins 更新中心直接获取。如果 <code>Jenkins</code> 更新中心地址（升级站点）不是 <a href="https://updates.jenkins.io/update-center.json" target="_blank" rel="noreferrer">官方镜像源</a>，通常无法检索到最新版本。</p><h2 id="离线安装" tabindex="-1">离线安装 <a class="header-anchor" href="#离线安装" aria-label="Permalink to “离线安装”">​</a></h2><p>建议优先通过发布页下载插件包：</p><ul><li><a href="https://github.com/721806280/lark-notice-plugin/releases" target="_blank" rel="noreferrer">GitHub Releases</a></li><li><a href="https://gitee.com/xm721806280/lark-notice-plugin/releases" target="_blank" rel="noreferrer">Gitee Releases</a></li></ul><p>在 Jenkins 中安装插件的步骤如下：</p><ol><li>打开 <code>系统管理</code> -&gt; <code>插件管理</code>。</li><li>进入 <code>Advanced</code> 或 <code>高级</code> 页面。</li><li>在 <code>Deploy Plugin</code> 区域上传下载好的插件包，或填写插件地址。</li><li>提交安装并按提示完成 Jenkins 重启。</li></ol><h2 id="机器人配置" tabindex="-1">机器人配置 <a class="header-anchor" href="#机器人配置" aria-label="Permalink to “机器人配置”">​</a></h2><h3 id="全局配置" tabindex="-1">全局配置 <a class="header-anchor" href="#全局配置" aria-label="Permalink to “全局配置”">​</a></h3><p>打开 <code>Manage Jenkins</code> 页面，找到 <code>Lark Notice</code> 配置项。</p><p><img src="'+s+'" alt=""></p><p>进入全局配置页面后，可新增机器人、配置签名校验和通知时机等参数。</p><p><img src="'+l+'" alt=""></p><h3 id="添加机器人" tabindex="-1">添加机器人 <a class="header-anchor" href="#添加机器人" aria-label="Permalink to “添加机器人”">​</a></h3><p>添加机器人时，请根据目标平台填写对应的 <code>Webhook</code>、<code>加密密钥</code> 及相关配置项。</p><p><img src="'+n+`" alt=""></p><h3 id="jenkins-重启" tabindex="-1">Jenkins 重启 <a class="header-anchor" href="#jenkins-重启" aria-label="Permalink to “Jenkins 重启”">​</a></h3><p>插件安装或关键配置调整完成后，可通过以下地址执行 Jenkins 重启：</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 重启服务</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://[jenkins-server-address][:port]/restart</span></span></code></pre></div>`,24)])])}const _=a(o,[["render",d]]);export{m as __pageData,_ as default};
